const leadName = ($json.lead_name || '').trim();
const company = ($json.company || '').trim();
const role = ($json.role || '').trim();
const url = ($json.linkedin_url || '').trim();
const website = ($json.website || '').trim();
const note = ($json.manual_note || '').trim();
const leadSource = ($json.lead_source || '').trim();

const text = `${leadName} ${company} ${role} ${url} ${website} ${note} ${leadSource}`.toLowerCase();

const hasAny = (...terms) => terms.some(term => text.includes(term));

let segment = 'Unknown';
let contactType = 'Unknown';
let productFit = 'Unknown';
let outreachTrack = 'Nurture';
let examFocus = 'Unknown';
let roleSeniority = 'Unknown';
let audienceType = 'Unknown';

if (hasAny('oet') && (hasAny('ielts') || hasAny('toefl') || hasAny('celpip'))) {
  examFocus = 'Mixed';
} else if (hasAny('oet')) {
  examFocus = 'OET';
} else if (hasAny('ielts')) {
  examFocus = 'IELTS';
} else if (hasAny('toefl')) {
  examFocus = 'TOEFL';
} else if (hasAny('celpip')) {
  examFocus = 'CELPIP';
}

if (hasAny('academy', 'institute', 'training center', 'test prep', 'prep center', 'language center')) {
  audienceType = 'Academy';
} else if (hasAny('school', 'university', 'college')) {
  audienceType = 'School';
} else if (hasAny('solo', 'freelance', 'independent tutor', 'private tutor')) {
  audienceType = 'Solo Teacher';
} else if (hasAny('test prep', 'prep center', 'exam prep')) {
  audienceType = 'Test Prep Center';
}

if (hasAny('founder')) {
  roleSeniority = 'Founder';
} else if (hasAny('owner', 'co-owner')) {
  roleSeniority = 'Owner';
} else if (hasAny('director', 'head of', 'principal', 'ceo')) {
  roleSeniority = 'Director';
} else if (hasAny('manager', 'administrator', 'admin')) {
  roleSeniority = 'Manager';
} else if (hasAny('coordinator', 'head teacher', 'lead teacher', 'academic manager', 'department head')) {
  roleSeniority = 'Coordinator';
} else if (hasAny('teacher', 'tutor', 'instructor', 'lecturer', 'examiner')) {
  roleSeniority = 'Teacher';
}

if (hasAny('teacher', 'tutor', 'instructor', 'lecturer', 'examiner')) {
  segment = 'Teacher';
}
if (hasAny('owner', 'founder', 'director', 'manager', 'administrator', 'admin', 'principal', 'ceo', 'co-founder')) {
  segment = 'Owner/Admin';
}
if (hasAny('academy', 'school', 'institute', 'training center', 'prep center', 'language center')) {
  segment = 'Academy';
}

const isTeacher = hasAny('teacher', 'tutor', 'instructor', 'lecturer', 'examiner');
const isDecisionMaker = hasAny('owner', 'founder', 'director', 'manager', 'administrator', 'admin', 'principal', 'ceo', 'co-founder');
const isBoth = hasAny('coordinator', 'head teacher', 'lead teacher', 'academic manager', 'department head');

if (isBoth) {
  contactType = 'Both';
} else if (isDecisionMaker) {
  contactType = 'Decision Maker';
} else if (isTeacher) {
  contactType = 'Teacher';
}

if (contactType === 'Decision Maker' && (audienceType === 'Academy' || audienceType === 'School' || audienceType === 'Test Prep Center')) {
  productFit = 'Blog Content Generator';
} else if (contactType === 'Teacher') {
  productFit = 'Teacher Tool';
} else if (contactType === 'Both') {
  productFit = 'Both';
}

if (contactType === 'Decision Maker' && productFit === 'Blog Content Generator') {
  outreachTrack = 'DM-Content';
} else if (contactType === 'Teacher' && productFit === 'Teacher Tool') {
  outreachTrack = 'Teacher-Product';
} else if (contactType === 'Teacher') {
  outreachTrack = 'Teacher-Relationship';
} else if (contactType === 'Both') {
  outreachTrack = 'Nurture';
} else if (contactType === 'Unknown' && !company && !website) {
  outreachTrack = 'Ignore';
}

let stage = 'New';
let nextAction = 'Review';

if (outreachTrack === 'DM-Content') {
  nextAction = 'Review and decide whether to send connection request';
} else if (outreachTrack === 'Teacher-Product') {
  nextAction = 'Review for teacher-product outreach';
} else if (outreachTrack === 'Teacher-Relationship') {
  nextAction = 'Review for soft relationship-building outreach';
} else if (outreachTrack === 'Nurture') {
  nextAction = 'Review and nurture later';
} else if (outreachTrack === 'Ignore') {
  nextAction = 'No action';
}

let fitScore = 50;

if (contactType === 'Decision Maker') fitScore += 20;
if (productFit === 'Both') fitScore += 15;
if (productFit === 'Blog Content Generator' && (audienceType === 'Academy' || audienceType === 'Test Prep Center' || audienceType === 'School')) fitScore += 15;
if (examFocus === 'OET') fitScore += 10;
if (website) fitScore += 10;
if (company) fitScore += 5;
if (note) fitScore += 5;

if (contactType === 'Unknown') fitScore -= 15;
if (productFit === 'Unknown') fitScore -= 15;
if (!company && !website) fitScore -= 10;
if (segment === 'Unknown' && !note && !role) fitScore -= 10;

fitScore = Math.max(0, Math.min(100, fitScore));

const fitLabel = fitScore >= 75 ? 'High' : fitScore >= 60 ? 'Medium' : 'Low';
const priorityGuess = fitLabel === 'High' ? 'High' : fitLabel === 'Medium' ? 'Medium' : 'Low';

const today = new Date().toISOString().split('T')[0];

return {
  json: {
    ...$json,
    segment_guess: segment,
    contact_type_guess: contactType,
    product_fit_guess: productFit,
    outreach_track_guess: outreachTrack,
    exam_focus_guess: examFocus,
    role_seniority_guess: roleSeniority,
    audience_type_guess: audienceType,
    priority_guess: priorityGuess,
    stage_default: stage,
    next_action: nextAction,
    fit_score: fitScore,
    fit_label: fitLabel,
    today
  }
};

let content =
  $json.text ||
  $json.response?.text ||
  $json.content ||
  '{}';

content = String(content).trim();

content = content
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

const firstBrace = content.indexOf('{');
const lastBrace = content.lastIndexOf('}');

if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  content = content.slice(firstBrace, lastBrace + 1);
}

let ai = {};
try {
  ai = JSON.parse(content);
} catch (e) {
  ai = {};
}

const base = $json;

const scoreAdj = Number(ai.fit_score_adjustment || 0);
let finalScore = Number(base.fit_score || 0) + scoreAdj;
finalScore = Math.max(0, Math.min(100, finalScore));

const finalFitLabel =
  finalScore >= 75 ? 'High' :
  finalScore >= 60 ? 'Medium' :
  'Low';

const finalPriority =
  ai.priority ||
  base.priority_guess ||
  (finalFitLabel === 'High' ? 'High' : finalFitLabel === 'Medium' ? 'Medium' : 'Low');

const finalSegment = ai.segment_final || base.segment_guess || 'Unknown';
const finalContactType = ai.contact_type || base.contact_type_guess || 'Unknown';
const finalProductFit = ai.product_fit || base.product_fit_guess || 'Unknown';
const finalOutreachTrack = ai.outreach_track || base.outreach_track_guess || 'Nurture';
const finalExamFocus = ai.exam_focus || base.exam_focus_guess || 'Unknown';
const finalRoleSeniority = ai.role_seniority || base.role_seniority_guess || 'Unknown';
const finalAudienceType = ai.audience_type || base.audience_type_guess || 'Unknown';
const finalRole = ai.role_guess || base.role || '';
const finalCompany = ai.company_guess || base.company || '';
const finalWebsite = ai.website_guess || base.website || '';
const finalRecommendedFirstStep = ai.recommended_first_step || base.next_action || 'Review';
const finalStage = base.stage_default || 'New';
const finalNextAction = finalRecommendedFirstStep === 'Ignore' ? 'No action' : finalRecommendedFirstStep;

return {
  json: {
    ...base,
    role_final: finalRole,
    company_final: finalCompany,
    website_final: finalWebsite,
    segment_final: finalSegment,
    contact_type_final: finalContactType,
    product_fit_final: finalProductFit,
    outreach_track_final: finalOutreachTrack,
    exam_focus_final: finalExamFocus,
    role_seniority_final: finalRoleSeniority,
    audience_type_final: finalAudienceType,
    pain_point_guess: ai.pain_point_guess || '',
    ai_summary: ai.ai_summary || '',
    personalization_angle: ai.personalization_angle || '',
    recommended_first_step: finalRecommendedFirstStep,
    next_action_final: finalNextAction,
    fit_score_final: finalScore,
    fit_label_final: finalFitLabel,
    priority_final: finalPriority,
    stage_final: finalStage,
    next_action_date: base.today || '',
    last_contact_date: '',
    overview_sent: 'No',
    booked_call: 'No'
  }
};

